import numpy as np

class DecisionTreeClassifier:
    def __init__(self, max_depth: int = 5, min_samples_split: int = 2):
        self.max_depth = max_depth
        self.min_samples_split = min_samples_split
        self.tree = None

    def _gini(self, y):
        if len(y) == 0:
            return 0.0
        classes, counts = np.unique(y, return_counts=True)
        probs = counts / len(y)
        return 1.0 - np.sum(probs ** 2)

    def _best_split(self, X, y):
        n, d = X.shape
        best_gini = float('inf')
        best_feat, best_thresh = None, None

        for feat in range(d):
            vals = np.sort(np.unique(X[:, feat]))
            thresholds = (vals[:-1] + vals[1:]) / 2  # midpoints
            for thresh in thresholds:
                left_mask = X[:, feat] <= thresh
                right_mask = ~left_mask
                n_l, n_r = left_mask.sum(), right_mask.sum()
                if n_l == 0 or n_r == 0:
                    continue
                g = (n_l / n) * self._gini(y[left_mask]) + (n_r / n) * self._gini(y[right_mask])
                if g < best_gini:
                    best_gini = g
                    best_feat = feat
                    best_thresh = thresh
        return best_feat, best_thresh

    def _build(self, X, y, depth):
        # Stopping conditions
        if depth >= self.max_depth or len(y) < self.min_samples_split or len(np.unique(y)) == 1:
            return {'leaf': True, 'label': int(np.bincount(y).argmax())}

        feat, thresh = self._best_split(X, y)
        if feat is None:
            return {'leaf': True, 'label': int(np.bincount(y).argmax())}

        left_mask = X[:, feat] <= thresh
        return {
            'leaf': False,
            'feat': feat,
            'thresh': thresh,
            'left': self._build(X[left_mask], y[left_mask], depth + 1),
            'right': self._build(X[~left_mask], y[~left_mask], depth + 1)
        }

    def fit(self, X: np.ndarray, y: np.ndarray) -> None:
        self.tree = self._build(X, y, 0)

    def _predict_one(self, x, node):
        if node['leaf']:
            return node['label']
        if x[node['feat']] <= node['thresh']:
            return self._predict_one(x, node['left'])
        return self._predict_one(x, node['right'])

    def predict(self, X: np.ndarray) -> np.ndarray:
        return np.array([self._predict_one(x, self.tree) for x in X])
